StructuredTextModel.Text:
IF (Enable) THEN
	Shear_Down_R(CLK := Shear_Down);
	
	// Time in-between each punch
	Punch_Timer(In := (NOT Timer_Reset), PT := T#100s);
	Timer_Reset := FALSE;

	// Add our times together to get an accurate reading
	IF (Shear_Down_R.Q) THEN
			Punch_Time[I] := (LINT_TO_REAL(TimeToNanoSec(Punch_Timer.ET)))*REAL#10.0**-9;
			
			// Increase the index for each new value saved
			I := I +1;
			IF (I >= UINT_TO_INT(SizeOfAry(Punch_Time))) THEN
				I := 0;
			END_IF;
			// Reset the timer
			Timer_Reset := TRUE;
	END_IF;
	
	SPM := 0;
	FOR J := 0 TO (UINT_TO_INT(SizeOfAry(Punch_Time))-1) DO
		SPM := SPM + Punch_Time[J];
	END_FOR;
	
	// SPM in seconds per punch
	SPM := SPM/4;
	// Convert to punches per minute
	SPM := SafeDiv_REAL(60, SPM);
ELSE
	// Initialize all values when the shear is not running
	SPM := 0;
	I := 0;
	Punch_Time := Punch_Time_Init;
END_IF;
